import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import * as yup from "yup";
import { useFormik } from "formik";
import { useDispatch, useSelector } from "react-redux";
import { login } from "../features/auth/authSlice";
import { Mail, Lock, ShieldCheck, Zap, Activity } from "lucide-react";

let schema = yup.object().shape({
  email: yup
    .string()
    .email("Email should be valid")
    .required("Email is Required"),
  password: yup.string().required("Password is Required"),
});

const Login = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const { user, isError, isSuccess, isLoading, message } = useSelector(
    (state) => state.auth,
  );

  const formik = useFormik({
    initialValues: {
      email: "",
      password: "",
    },
    validationSchema: schema,
    onSubmit: (values) => {
      dispatch(login(values));
    },
  });

  useEffect(() => {
    if (isSuccess && user) {
      const roleRedirectMap = {
        admin: "/admin",
        deliveryBoy: "/delivery",
        superAdmin: "/superAdmin",
        merchant: "/merchant",
      };
      const redirectPath = roleRedirectMap[user.role];
      if (redirectPath) {
        navigate(redirectPath);
      }
    }
  }, [user, isError, isSuccess, navigate]);

  return (
    <div
      className="flex items-center justify-center min-h-screen font-sans p-4 relative overflow-hidden"
      style={{
        background:
          "linear-gradient(135deg, #0f172a 0%, #1e3a8a 50%, #172554 100%)",
      }}
    >
      {/* Background decoration */}
      <div className="absolute inset-0 overflow-hidden">
        <div className="absolute top-[-20%] right-[-10%] w-[600px] h-[600px] bg-[#257CB7]/10 rounded-full blur-3xl" />
        <div className="absolute bottom-[-20%] left-[-10%] w-[500px] h-[500px] bg-[#90CAF9]/10 rounded-full blur-3xl" />
      </div>

      <div className="w-full max-w-md relative z-10">
        {/* Logo Header */}
        <div className="text-center mb-10">
          <div className="inline-flex items-center justify-center w-16 h-16 bg-gradient-to-br from-[#90CAF9] to-[#257CB7] rounded-2xl shadow-2xl shadow-blue-500/30 mb-6 ring-2 ring-white/20">
            <Zap size={32} className="text-white" fill="currentColor" />
          </div>
          <h1 className="text-3xl font-black text-white tracking-tighter mb-2">
            Pulse Addis
          </h1>
          <p className="text-[10px] font-black text-[#90CAF9] uppercase tracking-[0.4em]">
            Management System
          </p>
        </div>

        {/* Login Card */}
        <div className="bg-white/10 backdrop-blur-xl rounded-3xl shadow-2xl p-10 space-y-8 border border-white/10">
          <div className="text-center">
            <h2 className="text-2xl font-black text-white tracking-tight">
              Welcome Back
            </h2>
            <p className="mt-2 text-sm text-blue-200/60 font-medium">
              Sign in to access the admin dashboard
            </p>
          </div>

          <form onSubmit={formik.handleSubmit} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-blue-200/60 tracking-widest flex items-center gap-2">
                <Mail size={12} /> Email Address
              </label>
              <div className="relative">
                <Mail
                  className="absolute top-1/2 left-4 -translate-y-1/2 text-blue-300/40"
                  size={18}
                />
                <input
                  type="text"
                  id="email"
                  name="email"
                  placeholder="admin@pulseaddis.com"
                  onChange={formik.handleChange("email")}
                  onBlur={formik.handleBlur("email")}
                  value={formik.values.email}
                  className="w-full pl-12 pr-4 py-4 bg-white/5 text-white border border-white/10 rounded-2xl focus:outline-none focus:ring-2 focus:ring-[#257CB7] focus:border-transparent transition-all duration-300 placeholder-blue-200/30 font-medium"
                />
              </div>
              {formik.touched.email && formik.errors.email && (
                <p className="text-rose-400 text-[10px] uppercase font-black tracking-widest pl-4">
                  {formik.errors.email}
                </p>
              )}
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-blue-200/60 tracking-widest flex items-center gap-2">
                <Lock size={12} /> Password
              </label>
              <div className="relative">
                <Lock
                  className="absolute top-1/2 left-4 -translate-y-1/2 text-blue-300/40"
                  size={18}
                />
                <input
                  type="password"
                  id="password"
                  name="password"
                  placeholder="Your secure password"
                  onChange={formik.handleChange("password")}
                  onBlur={formik.handleBlur("password")}
                  value={formik.values.password}
                  className="w-full pl-12 pr-4 py-4 bg-white/5 text-white border border-white/10 rounded-2xl focus:outline-none focus:ring-2 focus:ring-[#257CB7] focus:border-transparent transition-all duration-300 placeholder-blue-200/30 font-medium"
                />
              </div>
              {formik.touched.password && formik.errors.password && (
                <p className="text-rose-400 text-[10px] uppercase font-black tracking-widest pl-4">
                  {formik.errors.password}
                </p>
              )}
            </div>

            {isError && (
              <div className="flex items-center gap-3 text-rose-300 text-sm font-bold p-4 bg-rose-500/10 rounded-2xl border border-rose-500/20">
                <ShieldCheck size={16} />
                {message.message === "Rejected"
                  ? "Authorization Failed"
                  : "Invalid email or password."}
              </div>
            )}

            <button
              type="submit"
              disabled={isLoading}
              className={`w-full font-black py-4 px-4 rounded-2xl text-white transition-all duration-300 ease-in-out focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-transparent focus:ring-[#257CB7] uppercase tracking-widest text-xs shadow-xl shadow-blue-500/20
                ${
                  isLoading
                    ? "bg-[#257CB7]/60 cursor-not-allowed"
                    : "bg-[#257CB7] hover:bg-[#1e6aa0] hover:translate-y-[-2px]"
                }
              `}
            >
              {isLoading ? (
                <div className="flex items-center justify-center gap-3">
                  <svg
                    className="animate-spin h-5 w-5 text-white"
                    xmlns="http://www.w3.org/2000/svg"
                    fill="none"
                    viewBox="0 0 24 24"
                  >
                    <circle
                      className="opacity-25"
                      cx="12"
                      cy="12"
                      r="10"
                      stroke="currentColor"
                      strokeWidth="4"
                    ></circle>
                    <path
                      className="opacity-75"
                      fill="currentColor"
                      d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                    ></path>
                  </svg>
                  <span>Authenticating...</span>
                </div>
              ) : (
                "Access Dashboard"
              )}
            </button>
          </form>

          <div className="text-center">
            <button className="text-[10px] text-blue-200/40 font-black hover:text-white hover:underline transition-colors duration-300 focus:outline-none uppercase tracking-widest">
              Forgot Password? Contact Super Admin
            </button>
          </div>
        </div>

        {/* Footer */}
        <div className="text-center mt-8 flex items-center justify-center gap-4">
          <span className="flex items-center gap-2 text-[9px] font-black uppercase tracking-widest text-blue-200/30">
            <ShieldCheck size={10} /> Secure Connection
          </span>
          <span className="flex items-center gap-2 text-[9px] font-black uppercase tracking-widest text-blue-200/30">
            <Activity size={10} /> Pulse Addis © 2026
          </span>
        </div>
      </div>
    </div>
  );
};

export default Login;
